  1	import { type FC, useMemo } from 'react';
  2	import { useForkliftTranslation } from 'src/utils/i18n';
  3	
  4	import {
  5	  NetworkMapModelGroupVersionKind,
  6	  StorageMapModelGroupVersionKind,
  7	  type V1beta1Plan,
  8	} from '@kubev2v/types';
  9	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 10	import {
 11	  DescriptionList,
 12	  DescriptionListDescription,
 13	  DescriptionListGroup,
 14	  DescriptionListTerm,
 15	  Drawer,
 16	  Split,
 17	  SplitItem,
 18	} from '@patternfly/react-core';
 19	import {
 20	  getPlanNetworkMapName,
 21	  getPlanNetworkMapNamespace,
 22	  getPlanStorageMapName,
 23	  getPlanStorageMapNamespace,
 24	} from '@utils/crds/plans/selectors';
 25	
 26	import { IgnoreNetwork } from '../utils/constants';
 27	import type { Mapping } from '../utils/types';
 28	
 29	import MappingList from './MappingList';
 30	
 31	type PlanMappingsEditModeProps = {
 32	  plan: V1beta1Plan;
 33	  labeledNetworkMappings: Mapping[];
 34	  labeledStorageMappings: Mapping[];
 35	  availableNetworkSources: string[];
 36	  availableNetworkTargets: string[];
 37	  availableStorageSources: string[];
 38	  availableStorageTargets: string[];
 39	  onAddNetwork: () => void;
 40	  onDeleteNetwork: (current: Mapping) => void;
 41	  onReplaceNetwork: (args: { current: Mapping; next: Mapping }) => void;
 42	  onAddStorage: () => void;
 43	  onDeleteStorage: (current: Mapping) => void;
 44	  onReplaceStorage: (args: { current: Mapping; next: Mapping }) => void;
 45	  disableAddNetwork: boolean;
 46	  disableAddStorage: boolean;
 47	};
 48	
 49	const PlanMappingsEditMode: FC<PlanMappingsEditModeProps> = ({
 50	  availableNetworkSources,
 51	  availableNetworkTargets,
 52	  availableStorageSources,
 53	  availableStorageTargets,
 54	  disableAddNetwork,
 55	  disableAddStorage,
 56	  labeledNetworkMappings,
 57	  labeledStorageMappings,
 58	  onAddNetwork,
 59	  onAddStorage,
 60	  onDeleteNetwork,
 61	  onDeleteStorage,
 62	  onReplaceNetwork,
 63	  onReplaceStorage,
 64	  plan,
 65	}) => {
 66	  const { t } = useForkliftTranslation();
 67	
 68	  const filteredNetworkTargets = useMemo(
 69	    () => availableNetworkTargets.filter((target) => target !== IgnoreNetwork.Label),
 70	    [availableNetworkTargets],
 71	  );
 72	
 73	  return (
 74	    <Drawer>
 75	      <DescriptionList columnModifier={{ default: '1Col' }}>
 76	        <DescriptionListGroup data-testid="network-mappings-section">
 77	          <DescriptionListTerm>
 78	            <Split hasGutter>
 79	              <SplitItem>{t('Network map:')}</SplitItem>
 80	              <SplitItem>
 81	                <ResourceLink
 82	                  groupVersionKind={NetworkMapModelGroupVersionKind}
 83	                  name={getPlanNetworkMapName(plan)}
 84	                  namespace={getPlanNetworkMapNamespace(plan)}
 85	                  inline
 86	                />
 87	              </SplitItem>
 88	            </Split>
 89	          </DescriptionListTerm>
 90	          <DescriptionListDescription>
 91	            <MappingList
 92	              mappings={labeledNetworkMappings}
 93	              availableSources={availableNetworkSources}
 94	              availableDestinations={filteredNetworkTargets}
 95	              additionalDestinations={[IgnoreNetwork.Label]}
 96	              deleteMapping={onDeleteNetwork}
 97	              addMapping={onAddNetwork}
 98	              replaceMapping={onReplaceNetwork}
 99	              generalSourcesLabel={t('Other networks present on the source provider ')}
100	              noSourcesLabel={t('No networks in this category')}
101	              isDisabled={disableAddNetwork}
102	              testId="network-mappings-list"
103	            />
104	          </DescriptionListDescription>
105	        </DescriptionListGroup>
106	
107	        <DescriptionListGroup data-testid="storage-mappings-section">
108	          <DescriptionListTerm>
109	            <Split hasGutter>
110	              <SplitItem>{t('Storage map:')}</SplitItem>
111	              <SplitItem>
112	                <ResourceLink
113	                  groupVersionKind={StorageMapModelGroupVersionKind}
114	                  namespace={getPlanStorageMapNamespace(plan)}
115	                  name={getPlanStorageMapName(plan)}
116	                  inline
117	                />
118	              </SplitItem>
119	            </Split>
120	          </DescriptionListTerm>
121	          <DescriptionListDescription>
122	            <MappingList
123	              mappings={labeledStorageMappings}
124	              availableSources={availableStorageSources}
125	              availableDestinations={availableStorageTargets}
126	              deleteMapping={onDeleteStorage}
127	              addMapping={onAddStorage}
128	              replaceMapping={onReplaceStorage}
129	              generalSourcesLabel={t('Other storages present on the source provider ')}
130	              noSourcesLabel={t('No storages in this category')}
131	              isDisabled={disableAddStorage}
132	              testId="storage-mappings-list"
133	            />
134	          </DescriptionListDescription>
135	        </DescriptionListGroup>
136	      </DescriptionList>
137	    </Drawer>
138	  );
139	};
140	
141	export default PlanMappingsEditMode;

